func solve(nums []int64) bool {
    n := len(nums)
    if n < 3 {
        return false
    }

    prefix := make([]bool, n)
    suffix := make([]bool, n)
    dec := make([][]bool, n)
    for i := range dec {
        dec[i] = make([]bool, n)
    }

    prefix[0] = true
    for i := 1; i < n; i++ {
        prefix[i] = prefix[i-1] && (nums[i-1] < nums[i])
    }

    suffix[n-1] = true
    for i := n-2; i >= 0; i-- {
        suffix[i] = (nums[i] < nums[i+1]) && suffix[i+1]
    }

    for start := 0; start < n; start++ {
        dec[start][start] = true
        if start < n-1 {
            dec[start][start+1] = nums[start] > nums[start+1]
        }
        for end := start+2; end < n; end++ {
            dec[start][end] = dec[start][end-1] && (nums[end-1] > nums[end])
        }
    }

    for p := 1; p <= n-3; p++ {
        for q := p+1; q <= n-2; q++ {
            if prefix[p] && dec[p][q] && suffix[q] {
                return true
            }
        }
    }
    return false
}
```

